using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.AI;

public class MonsterObject : MonoBehaviour
{
    private Animator animator;
    private NavMeshAgent agent;
    private MonsterInfo monsterInfo;

    private int hp;
    public bool isDead = false;

    void Awake()
    {
        animator = GetComponent<Animator>();
        agent = GetComponent<NavMeshAgent>();
    }

    public void Init(MonsterInfo info)
    {
        monsterInfo = info;
        animator.runtimeAnimatorController = Resources.Load<RuntimeAnimatorController>(info.animator);
        hp = info.hp;
        agent.speed = agent.acceleration = info.moveSpeed;
        agent.angularSpeed = info.roundSpeed;
    }

    public void TakeDamage(int damage)
    {
        if (isDead) return;
        hp -= damage;
        animator.SetTrigger("hurted");
        if (hp <= 0)
        {
            Die();
        }
        else
        {
            //播放受伤音效
        }
    }

    public void Die()
    {
        isDead = true;
        animator.SetBool("dead", true);
        //播放死亡音效
        //加钱
        agent.isStopped = true;
        Destroy(gameObject, 3f);
    }

    public void DeadEvent()
    {

    }

    public void BornOver()
    {
        agent.SetDestination(PlayerObject.Instance.transform.position);
        animator.SetBool("run", true);
    }

    public void AttackEvent()
    {
        if (isDead) return;
        Collider[] hitColliders = Physics.OverlapSphere(this.transform.position + this.transform.forward +this.transform.up, 1 , 1 << LayerMask.NameToLayer("Player"));
        for (int i = 0; i < hitColliders.Length; i++)
        {
            if (PlayerObject.Instance.gameObject == hitColliders[i].gameObject)
            {
                hitColliders[i].GetComponent<PlayerObject>().Wound(monsterInfo.atk);
            }
        }
    }

    public void Update()
    {
        if (isDead) return;
        if (agent.remainingDistance <= agent.stoppingDistance)
        {
            animator.SetBool("run", false);
            animator.SetTrigger("attack");
        }
        else
        {
            animator.SetBool("run", true);
        }
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

public class PlayerObject : MonoBehaviour
{
    //玩家对象的属性
    private int hp = 100; //玩家的生命值
    private int maxHp = 100;
    private int atk;
    private int money;
    private float ratate = 100;
    private bool isDead;
    private Animator animator;
    public Transform shootPoint;

    void Start()
    {
        animator = GetComponent<Animator>();

        RoleInfo roleInfo = GameDataManager.Instance.NowRoleInfo;
        if (roleInfo != null)
        {
            InitPlayerInfo(roleInfo.hp, 10, GameDataManager.Instance.playerData.havaMoney);
        }
        else
        {
            InitPlayerInfo(hp, atk, money);
        }
    }

    // Update is called once per frame
    void Update()
    {
        if (Input.GetKeyDown(KeyCode.K))
            Wound(10);

        if (isDead)
        {
            return;
        }
        //移动，动作变化
        animator.SetFloat("VSpeed", Input.GetAxis("Vertical"));
        animator.SetFloat("HSpeed", Input.GetAxis("Horizontal"));

        this.transform.Rotate(Vector3.up * Input.GetAxis("Mouse X") * ratate * Time.deltaTime);

        //蹲
        if (Input.GetKey(KeyCode.LeftControl))
        {
            animator.SetLayerWeight(1, 1);
        }
        else if (Input.GetKeyUp(KeyCode.LeftControl))
        {
            animator.SetLayerWeight(1, 0);
        }

        //滚
        if (Input.GetKeyDown(KeyCode.Space))
        {
            animator.SetTrigger("Roll");
        }

        //攻击
        if (Input.GetMouseButtonDown(0))
        {
            animator.SetTrigger("Attack");
        }
    }

    public void InitPlayerInfo(int hp, int atk, int money)
    {
        this.hp = hp;
        this.maxHp = hp;
        this.atk = atk;
        this.money = money;
        UpdateMoney();
        UpdateBlood();
    }

    public void KnifeEvent()
    {
        Collider[] coliders = Physics.OverlapSphere(this.transform.position + this.transform.forward + this.transform.up, 1, 1 << LayerMask.NameToLayer("Enemy"));
        for (int i = 0; i < coliders.Length; i++)
        {
            // 处理击中的敌人
        }
    }

    public void ShotEvent()
    {
        RaycastHit[] hits = Physics.RaycastAll(new Ray(shootPoint.position, shootPoint.forward), 1000, 1 << LayerMask.NameToLayer("Enemy"));
        for (int i = 0; i < hits.Length; i++)
        {
            // 处理击中的敌人
        }
    }

    public void DeadEvent()
    {

    }

    //玩家受伤
    public void Wound(int value)
    {
        if (isDead || value <= 0)
        {
            return;
        }

        hp -= value;
        if (hp < 0)
        {
            hp = 0;
        }

        UpdateBlood();

        if (hp <= 0)
        {
            Dead();
        }
    }

    public void UpdateBlood()
    {
        GamePanel panel = UIManager.Instance.GetPanel<GamePanel>();
        if (panel != null)
        {
            panel.UpdateBlood(hp, maxHp);
        }
    }

    //玩家死亡
    private void Dead()
    {
        if (isDead)
        {
            return;
        }

        isDead = true;
        Cursor.lockState = CursorLockMode.None;
        animator.SetTrigger("Dead");
        UIManager.Instance.showPanel<TipPanel>().SetInfo("你死了！！！", () =>
        {
            SceneManager.LoadScene("BeginScene");

        });
    }

    //金钱
    public void UpdateMoney()
    {
        UIManager.Instance.GetPanel<GamePanel>().UpdateMoney(money);
    }

    public void AddMoney(int value)
    {
        money += value;
        UpdateMoney();
    }
}

